#include<bits/stdc++.h>
using namespace std;
int cnt[1001],a[1001];
int main()
{
    int k=0;
    int n,m1,m2;
    scanf("%d%d%d",&n,&m1,&m2);
    for(int i=2;i<=m1;i++)
    {
        if(m1%i==0)
        {
            cnt[++k]=0;
            a[k]=i;
            while(m1%i==0)
            {
                m1/=i;
                cnt[k]++;
            }
            cnt[k]*=m2;
        }
    }
    int ans=INT_MAX;
    for(int i=1;i<=n;i++)
    {
        int s,max1=0;
        scanf("%d",&s);
        for(int j=1;j<=k;j++)
        {
            int c=0;
            while(s%a[j]==0)
            {
                s/=a[j];
                c++;
            }
            if(c==0)
            {
                max1=INT_MAX;
            }
            else
            {
                max1=max(max1,(cnt[j]+c-1)/c);
            }
        }
        ans=min(ans,max1);
    }
    if(ans==INT_MAX)
    {
        printf("-1");
    }
    else
    {
        printf("%d",ans);
    }
    return 0;
}
